1	import { describe, it, expect } from "vitest";
2	import { processScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // Quote: base premiums and the processing fee
6	  it("empty item list → premium 5 G (only processing fee)", () => {
7	    const result = processScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	  it("quote a single plain sword → premium 105 G (100 base + 5 fee)", () => {
14	    const result = processScenario({
15	      customer: { yearsWithMHPCO: 0 },
16	      steps: [
17	        {
18	          op: "quote",
19	          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
20	        },
21	      ],
22	    });
23	    expect(result).toEqual({ results: [{ premium: 105 }] });
24	  });
25	  it.todo("quote a single plain amulet → premium 65 G (60 base + 5 fee)");
26	  it.todo("quote a single plain staff → premium 85 G (80 base + 5 fee)");
27	  it.todo("quote a single plain potion → premium 45 G (40 base + 5 fee)");
28	  it.todo("quote a sword and an amulet → premium 165 G (100 + 60 + 5 fee)");
29	
30	  // Components and the block-of-3 rule
31	  it.todo("quote 1 rune → premium 30 G (25 + 5 fee)");
32	  it.todo("quote 2 runes → premium 55 G (50 + 5 fee, no block)");
33	  it.todo("quote 3 runes → premium 65 G (block: 60 + 5 fee)");
34	  it.todo("quote 4 runes → premium 105 G (100 + 5 fee, no block)");
35	  it.todo("quote 7 runes → premium 180 G (175 + 5 fee, no block at 7)");
36	  it.todo("quote 2 runes + 1 moonstone → premium 80 G (75 + 5 fee, no block)");
37	  it.todo("quote 3 runes + 3 moonstones → premium 125 G (120 + 5 fee, two blocks)");
38	
39	  // Item-specific modifiers
40	  it.todo("cursed sword → premium 155 G (100 + 50 curse + 5 fee)");
41	  it.todo("sword with enchantment 5 → premium 135 G (100 + 30 high enchantment + 5 fee)");
42	  it.todo("sword with enchantment 4 → no high enchantment surcharge");
43	  it.todo("cursed sword with enchantment 5 → premium 185 G (100 + 50 + 30 + 5)");
44	
45	  // Policy-wide modifiers
46	  it.todo("first insurance: plain sword newcomer → premium 115 G (100 + 10 + 5)");
47	  it.todo("loyalty discount: plain sword for 2-year customer → premium 85 G (100 - 20 + 5)");
48	  it.todo("follow-up contract: plain sword on second contract → premium 90 G (100 - 15 + 5)");
49	
50	  // Multi-item modifier scope
51	  it.todo("cursed sword + plain amulet for newcomer → premium 231 G (100+60+50 curse +21 first ins +5)");
52	
53	  // Rounding
54	  it.todo("premium that yields 197.5 G → final 198 G (rounded up in MHPCO favor)");
55	
56	  // Integration examples
57	  it.todo("newcomer with cursed sword → premium 165 G");
58	  it.todo("long-standing customer second contract, cursed sword enchantment 7 → premium 160 G");
59	
60	  // Claim: basic payout
61	  it.todo("claim with plain sword damage 500 G → payout 400 G, remainingCap 1600 G");
62	  it.todo("claim with rune damage 200 G → payout 100 G");
63	  it.todo("claim with high-enchantment sword damage 1000 G → payout 400 G (50% then deductible)");
64	  it.todo("claim with dragon-material sword damage 1000 G → payout 900 G (full minus deductible)");
65	  it.todo("claim with dragon-material sword enchantment 9 damage 1000 G → payout 400 G (50% wins)");
66	  it.todo("claim with dragon-material sword enchantment 8 damage 1000 G → payout 400 G (50% applies)");
67	
68	  // Multiple damages, deductibles, and cap
69	  it.todo("claim with two damages (sword 500, amulet 300) → payout 600 G (deductible per item)");
70	  it.todo("cap exhaustion: two 1500 G claims on a sword → first payout 1400, then 600");
71	
72	  // Rounding payout
73	  it.todo("payout that yields 350.5 G → final 350 G (rounded down)");
74	
75	  // Error cases
76	  it.todo("quote with unknown item type → CLI non-zero exit, error to stderr");
77	  it.todo("claim referencing item not in policy → non-zero exit, error to stderr");
78	  it.todo("claim with negative damage amount → non-zero exit, error to stderr");
79	  it.todo("claim with more damages of a type than insured → non-zero exit");
80	});
