1	const PROCESSING_FEE = 5;
2	
3	type Item = { type: string };
4	type QuoteStep = { op: "quote"; items: Item[] };
5	type Step = QuoteStep;
6	type Scenario = { customer: unknown; steps: Step[] };
7	type QuoteResult = { premium: number };
8	type StepResult = QuoteResult;
9	
10	const basePremiumForItem = (item: Item): number => {
11	  if (item.type === "sword") return 100;
12	  return 0;
13	};
14	
15	const quote = (step: QuoteStep): QuoteResult => {
16	  const base = step.items.reduce((sum, item) => sum + basePremiumForItem(item), 0);
17	  return { premium: base + PROCESSING_FEE };
18	};
19	
20	export const processScenario = (input: Scenario): { results: StepResult[] } => {
21	  const results = input.steps.map((step) => quote(step));
22	  return { results };
23	};
